  ('social-worker-moex-07019', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據社會工作師法，下列有關「時間」的規定，何者正確？', '["社會工作師執行業務時，應撰製社會工作紀錄，紀錄保存年限不得少於七年", "申請設立社會工作師事務所之社會工作師，須執行社工相關業務六年以上，並得有工作證明者，始得為之", "社會工作師公會之理事長及理、監事任期最長為二年", "社會工作師停業、歇業、復業或變更行政區域時，應自事實發生之日起三十一日內，報請原發執業執 照機關備查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
